/**
 * Sets the plane to the given point and normal.
 *
 * @param point  the point on the plane
 * @param normal the normal of the plane
 */
public void set(Vector3 point, Vector3 normal) {
    this.normal.set(normal);
    d = -point.dot(normal);
}
